class RabbitMQConnection:
    """Manages RabbitMQ connection and channel creation."""

    def __init__(
        self,
        host: str = RABBITMQ_HOST,
        port: int = RABBITMQ_PORT,
        username: str = RABBITMQ_USER,
        password: str = RABBITMQ_PASSWORD,
        virtual_host: str = RABBITMQ_VHOST,
        heartbeat: int = 600,
        blocked_connection_timeout: int = 300,
    ):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.virtual_host = virtual_host
        self.heartbeat = heartbeat
        self.blocked_connection_timeout = blocked_connection_timeout
        self.connection: Optional[pika.BlockingConnection] = None
        self.channel: Optional[pika.channel.Channel] = None

    def connect(self) -> pika.channel.Channel:
        """Establish connection to RabbitMQ and return a channel."""
        credentials = pika.PlainCredentials(self.username, self.password)
        parameters = pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            virtual_host=self.virtual_host,
            credentials=credentials,
            heartbeat=self.heartbeat,
            blocked_connection_timeout=self.blocked_connection_timeout,
            connection_attempts=3,
            retry_delay=5,
        )

        self.connection = pika.BlockingConnection(parameters)
        self.channel = self.connection.channel()
        logger.info(f"Connected to RabbitMQ at {self.host}:{self.port}")
        return self.channel

    def close(self):
        """Close the connection gracefully."""
        if self.connection and not self.connection.is_closed:
            self.connection.close()
            logger.info("RabbitMQ connection closed")

    def __enter__(self):
        self.connect()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()


class QueueManager:
    """Declares exchanges, queues, and bindings for the task processing system."""

    @staticmethod
    def setup_infrastructure(channel: pika.channel.Channel):
        """Set up all exchanges, queues, and bindings."""
        # Declare Dead Letter Exchange and Queue
        channel.exchange_declare(
            exchange=DEAD_LETTER_EXCHANGE,
            exchange_type='direct',
            durable=True,
        )
        channel.queue_declare(
            queue=DEAD_LETTER_QUEUE,
            durable=True,
        )
        channel.queue_bind(
            queue=DEAD_LETTER_QUEUE,
            exchange=DEAD_LETTER_EXCHANGE,
            routing_key=DLX_ROUTING_KEY,
        )

        # Declare Task Exchange and Queue (with DLX support)
        channel.exchange_declare(
            exchange=TASK_EXCHANGE,
            exchange_type='direct',
            durable=True,
        )
        channel.queue_declare(
            queue=TASK_QUEUE,
            durable=True,
            arguments={
                'x-dead-letter-exchange': DEAD_LETTER_EXCHANGE,
                'x-dead-letter-routing-key': DLX_ROUTING_KEY,
                'x-message-ttl': 3600000,  # 1 hour TTL
                'x-max-length': 10000,
            },
        )
        channel.queue_bind(
            queue=TASK_QUEUE,
            exchange=TASK_EXCHANGE,
            routing_key=TASK_ROUTING_KEY,
        )

        # Declare Result Exchange and Queue
        channel.exchange_declare(
            exchange=RESULT_EXCHANGE,
            exchange_type='direct',
            durable=True,
        )
        channel.queue_declare(
            queue=RESULT_QUEUE,
            durable=True,
            arguments={
                'x-message-ttl': 86400000,  # 24 hour TTL
            },
        )
        channel.queue_bind(
            queue=RESULT_QUEUE,
            exchange=RESULT_EXCHANGE,
            routing_key=RESULT_ROUTING_KEY,
        )

        logger.info("RabbitMQ infrastructure set up successfully")


class Task:
    """Represents a task to be processed."""

    def __init__(
        self,
        task_type: str,
        payload: Dict[str, Any],
        task_id: Optional[str] = None,
        priority: int = 0,
        retry_count: int = 0,
        max_retries: int = 3,
    ):
        self.task_id = task_id or str(uuid.uuid4())
        self.task_type = task_type
        self.payload = payload
        self.priority = priority
        self.retry_count = retry_count
        self.max_retries = max_retries
        self.created_at = datetime.utcnow().isoformat()

    def to_dict(self) -> Dict[str, Any]:
        return {
            'task_id': self.task_id,
            'task_type': self.task_type,
            'payload': self.payload,
            'priority': self.priority,
            'retry_count': self.retry_count,
            'max_retries': self.max_retries,
            'created_at': self.created_at,
        }

    def to_json(self) -> str:
        return json.dumps(self.to_dict())

    @classmethod
    def from_json(cls, json_str: str) -> 'Task':
        data = json.loads(json_str)
        task = cls(
            task_type=data['task_type'],
            payload=data['payload'],
            task_id=data.get('task_id'),
            priority=data.get('priority', 0),
            retry_count=data.get('retry_count', 0),
            max_retries=data.get('max_retries', 3),
        )
        task.created_at = data.get('created_at', task.created_at)
        return task

    def __repr__(self):
        return f"Task(id={self.task_id}, type={self.task_type}, retry={self.retry_count}/{self.max_retries})"


class TaskResult:
    """Represents the result of a processed task."""

    def __init__(
        self,
        task_id: str,
        status: str,
        result: Any = None,
        error: Optional[str] = None,
    ):
        self.task_id = task_id
        self.status = status  # 'success', 'failure', 'retry'
        self.result = result
        self.error = error
        self.completed_at = datetime.utcnow().isoformat()

    def to_dict(self) -> Dict[str, Any]:
        return {
            'task_id': self.task_id,
            'status': self.status,
            'result': self.result,
            'error': self.error,
            'completed_at': self.completed_at,
        }

    def to_json(self) -> str:
        return json.dumps(self.to_dict())

    @classmethod
    def from_json(cls, json_str: str) -> 'TaskResult':
        data = json.loads(json_str)
        result = cls(
            task_id=data['task_id'],
            status=data['status'],
            result=data.get('result'),
            error=data.get('error'),
        )
        result.completed_at = data.get('completed_at', result.completed_at)
        return result


class TaskPublisher:
    """Publishes tasks to the RabbitMQ task queue."""

    def __init__(self, connection: Optional[RabbitMQConnection] = None):
        self._own_connection = connection is None
        self.conn = connection or RabbitMQConnection()
        self.channel: Optional[pika.channel.Channel] = None

    def connect(self):
        """Connect and set up infrastructure."""
        self.channel = self.conn.connect()
        QueueManager.setup_infrastructure(self.channel)
        # Enable publisher confirms
        self.channel.confirm_delivery()
        logger.info("TaskPublisher connected and ready")

    def publish_task(self, task: Task) -> bool:
        """
        Publish a single task to the task queue.
        Returns True if the message was confirmed by the broker.
        """
        if not self.channel or self.channel.is_closed:
            self.connect()

        properties = pika.BasicProperties(
            delivery_mode=2,  # Persistent
            content_type='application/json',
            message_id=task.task_id,
            timestamp=int(time.time()),
            priority=task.priority,
            headers={
                'task_type': task.task_type,
                'retry_count': task.retry_count,
            },
        )

        try:
            self.channel.basic_publish(
                exchange=TASK_EXCHANGE,
                routing_key=TASK_ROUTING_KEY,
                body=task.to_json(),
                properties=properties,
                mandatory=True,
            )
            logger.info(f"Published task: {task}")
            return True
        except pika.exceptions.UnroutableError:
            logger.error(f"Task could not be routed: {task}")
            return False
        except pika.exceptions.NackError:
            logger.error(f"Task was nacked by broker: {task}")
            return False
        except Exception as e:
            logger.error(f"Failed to publish task {task}: {e}")
            return False

    def publish_batch(self, tasks: list) -> Dict[str, bool]:
        """Publish a batch of tasks. Returns dict of task_id -> success."""
        results = {}
        for task in tasks:
            results[task.task_id] = self.publish_task(task)
        return results

    def close(self):
        """Close the publisher connection."""
        if self._own_connection:
            self.conn.close()

    def __enter__(self):
        self.connect()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()


class TaskConsumer:
    """Consumes and processes tasks from the RabbitMQ task queue."""

    def __init__(
        self,
        connection: Optional[RabbitMQConnection] = None,
        prefetch_count: int = 1,
    ):
        self._own_connection = connection is None
        self.conn = connection or RabbitMQConnection()
        self.channel: Optional[pika.channel.Channel] = None
        self.prefetch_count = prefetch_count
        self._task_handlers: Dict[str, Callable] = {}
        self._default_handler: Optional[Callable] = None
        self._running = False

    def connect(self):
        """Connect and set up infrastructure."""
        self.channel = self.conn.connect()
        QueueManager.setup_infrastructure(self.channel)
        self.channel.basic_qos(prefetch_count=self.prefetch_count)
        logger.info("TaskConsumer connected and ready")

    def register_handler(self, task_type: str, handler: Callable):
        """Register a handler function for a specific task type."""
        self._task_handlers[task_type] = handler
        logger.info(f"Registered handler for task type: {task_type}")

    def set_default_handler(self, handler: Callable):
        """Set a default handler for unregistered task types."""
        self._default_handler = handler
        logger.info("Default task handler set")

    def _on_message(self, channel, method, properties, body):
        """Callback for processing received messages."""
        task = None
        try:
            task = Task.from_json(body.decode('utf-8'))
            logger.info(f"Received task: {task}")

            # Find the appropriate handler
            handler = self._task_handlers.get(task.task_type, self._default_handler)
            if handler is None:
                logger.warning(f"No handler for task type: {task.task_type}")
                # Reject and don't requeue — send to DLX
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return

            # Execute the handler
            result = handler(task)

            # Publish result
            self._publish_result(
                TaskResult(
                    task_id=task.task_id,
                    status='success',
                    result=result,
                )
            )

            # Acknowledge the message
            channel.basic_ack(delivery_tag=method.delivery_tag)
            logger.info(f"Task completed successfully: {task.task_id}")

        except Exception as e:
            logger.error(f"Error processing task: {e}", exc_info=True)

            if task and task.retry_count < task.max_retries:
                # Retry: republish with incremented retry count
                task.retry_count += 1
                logger.info(
                    f"Retrying task {task.task_id} "
                    f"(attempt {task.retry_count}/{task.max_retries})"
                )
                self._republish_for_retry(task)
                channel.basic_ack(delivery_tag=method.delivery_tag)
            else:
                # Max retries exceeded or no task — reject to DLX
                if task:
                    self._publish_result(
                        TaskResult(
                            task_id=task.task_id,
                            status='failure',
                            error=str(e),
                        )
                    )
                    logger.error(
                        f"Task {task.task_id} failed after "
                        f"{task.retry_count} retries"
                    )
                channel.basic_nack(
                    delivery_tag=method.delivery_tag, requeue=False
                )

    def _republish_for_retry(self, task: Task):
        """Republish a task for retry with a delay."""
        properties = pika.BasicProperties(
            delivery_mode=2,
            content_type='application/json',
            message_id=task.task_id,
            timestamp=int(time.time()),
            headers={
                'task_type': task.task_type,
                'retry_count': task.retry_count,
            },
        )

        # Simple delay before retry
        delay_seconds = min(2 ** task.retry_count, 60)
        time.sleep(delay_seconds)

        self.channel.basic_publish(
            exchange=TASK_EXCHANGE,
            routing_key=TASK_ROUTING_KEY,
            body=task.to_json(),
            properties=properties,
        )

    def _publish_result(self, result: TaskResult):
        """Publish a task result to the result queue."""
        try:
            properties = pika.BasicProperties(
                delivery_mode=2,
                content_type='application/json',
                correlation_id=result.task_id,
                timestamp=int(time.time()),
            )
            self.channel.basic_publish(
                exchange=RESULT_EXCHANGE,
                routing_key=RESULT_ROUTING_KEY,
                body=result.to_json(),
                properties=properties,
            )
            logger.debug(f"Published result for task: {result.task_id}")
        except Exception as e:
            logger.error(f"Failed to publish result: {e}")

    def start_consuming(self):
        """Start consuming messages from the task queue."""
        if not self.channel or self.channel.is_closed:
            self.connect()

        self.channel.basic_consume(
            queue=TASK_QUEUE,
            on_message_callback=self._on_message,
            auto_ack=False,
        )

        self._running = True
        logger.info("TaskConsumer started. Waiting for tasks...")

        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user")
            self.stop_consuming()

    def stop_consuming(self):
        """Stop consuming messages."""
        self._running = False
        if self.channel:
            self.channel.stop_consuming()
        logger.info("TaskConsumer stopped")

    def close(self):
        """Close the consumer connection."""
        self.stop_consuming()
        if self._own_connection:
            self.conn.close()

    def __enter__(self):
        self.connect()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()


class ResultConsumer:
    """Consumes task results from the result queue."""

    def __init__(self, connection: Optional[RabbitMQConnection] = None):
        self._own_connection = connection is None
        self.conn = connection or RabbitMQConnection()
        self.channel: Optional[pika.channel.Channel] = None
        self._result_callback: Optional[Callable] = None

    def connect(self):
        self.channel = self.conn.connect()
        QueueManager.setup_infrastructure(self.channel)
        self.channel.basic_qos(prefetch_count=10)
        logger.info("ResultConsumer connected and ready")

    def set_callback(self, callback: Callable):
        """Set callback for processing results."""
        self._result_callback = callback

    def _on_result(self, channel, method, properties, body):
        """Handle received result messages."""
        try:
            result = TaskResult.from_json(body.decode('utf-8'))
            logger.info(
                f"Received result for task {result.task_id}: "
                f"status={result.status}"
            )
            if self._result_callback:
                self._result_callback(result)
            channel.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            logger.error(f"Error processing result: {e}")
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    def start_consuming(self):
        if not self.channel or self.channel.is_closed:
            self.connect()

        self.channel.basic_consume(
            queue=RESULT_QUEUE,
            on_message_callback=self._on_result,
            auto_ack=False,
        )

        logger.info("ResultConsumer started. Waiting for results...")
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("ResultConsumer interrupted")
            self.close()

    def close(self):
        if self.channel and self.channel.is_open:
            self.channel.stop_consuming()
        if self._own_connection:
            self.conn.close()


