def handle_email_task(task: Task) -> Dict[str, Any]:
    """Handler for email sending tasks."""
    payload = task.payload
    recipient = payload.get('recipient', 'unknown')
    subject = payload.get('subject', 'No Subject')
    logger.info(f"Sending email to {recipient}: {subject}")
    # Simulate email sending
    time.sleep(1)
    return {
        'sent_to': recipient,
        'subject': subject,
        'message': 'Email sent successfully',
    }


def handle_data_processing_task(task: Task) -> Dict[str, Any]:
    """Handler for data processing tasks."""
    payload = task.payload
    dataset = payload.get('dataset', 'unknown')
    operation = payload.get('operation', 'unknown')
    logger.info(f"Processing dataset '{dataset}' with operation '{operation}'")
    # Simulate processing
    time.sleep(2)
    return {
        'dataset': dataset,
        'operation': operation,
        'records_processed': 1000,
        'message': 'Data processing completed',
    }


def handle_report_generation_task(task: Task) -> Dict[str, Any]:
    """Handler for report generation tasks."""
    payload = task.payload
    report_type = payload.get('report_type', 'generic')
    logger.info(f"Generating {report_type} report")
    # Simulate report generation
    time.sleep(3)
    return {
        'report_type': report_type,
        'file_path': f'/reports/{task.task_id}_{report_type}.pdf',
        'message': 'Report generated successfully',
    }


def default_task_handler(task: Task) -> Dict[str, Any]:
    """Default handler for unregistered task types."""
    logger.info(f"Default handler processing task type: {task.task_type}")
    time.sleep(0.5)
    return {
        'task_type': task.task_type,
        'message': 'Task processed with default handler',
    }


def handle_result(result: TaskResult):
    """Callback for processing task results."""
    if result.status == 'success':
        logger.info(
            f"✅ Task {result.task_id} succeeded: {result.result}"
        )
    else:
        logger.error(
            f"❌ Task {result.task_id} failed: {result.error}"
        )


