def run_publisher():
    """Run the publisher to send sample tasks."""
    sample_tasks = [
        Task(
            task_type='email',
            payload={
                'recipient': 'user@example.com',
                'subject': 'Welcome!',
                'body': 'Hello and welcome to our platform.',
            },
            priority=1,
        ),
        Task(
            task_type='data_processing',
            payload={
                'dataset': 'user_analytics',
                'operation': 'aggregate',
                'date_range': '2024-01-01/2024-01-31',
            },
            priority=2,
        ),
        Task(
            task_type='report_generation',
            payload={
                'report_type': 'monthly_sales',
                'format': 'pdf',
                'department': 'marketing',
            },
            priority=0,
        ),
        Task(
            task_type='email',
            payload={
                'recipient': 'admin@example.com',
                'subject': 'System Alert',
                'body': 'Disk usage above 90%.',
            },
            priority=3,
        ),
        Task(
            task_type='unknown_type',
            payload={'data': 'test'},
            priority=0,
        ),
    ]

    with TaskPublisher() as publisher:
        logger.info(f"Publishing {len(sample_tasks)} tasks...")
        results = publisher.publish_batch(sample_tasks)
        for task_id, success in results.items():
            status = "✅" if success else "❌"
            logger.info(f"  {status} Task {task_id}: {'published' if success else 'failed'}")
        logger.info("All tasks published")


def run_consumer():
    """Run the task consumer."""
    with TaskConsumer(prefetch_count=1) as consumer:
        consumer.register_handler('email', handle_email_task)
        consumer.register_handler('data_processing', handle_data_processing_task)
        consumer.register_handler('report_generation', handle_report_generation_task)
        consumer.set_default_handler(default_task_handler)
        consumer.start_consuming()


def run_result_consumer():
    """Run the result consumer."""
    result_consumer = ResultConsumer()
    result_consumer.connect()
    result_consumer.set_callback(handle_result)
    try:
        result_consumer.start_consuming()
    finally:
        result_consumer.close()


def run_setup():
    """Set up RabbitMQ infrastructure only."""
    with RabbitMQConnection() as conn:
        QueueManager.setup_infrastructure(conn.channel)
        logger.info("Infrastructure setup complete")


